import React, { useState } from 'react';
import { View, Button, Text, ActivityIndicator } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = AuthSession.makeRedirectUri();

export default function App() {
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    setLoading(true);
    const authUrl = `https://example.com/oauth/authorize?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`;
    const result = await AuthSession.startAsync({ authUrl });
    
    if (result.type === 'success') {
      const { code } = result.params;
      
      const tokenResponse = await fetch('https://example.com/oauth/token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `grant_type=authorization_code&code=${code}&redirect_uri=${encodeURIComponent(redirectUri)}&client_id=${clientId}&client_secret=${clientSecret}`
      });
      const data = await tokenResponse.json();
      setToken(data.access_token);
    }
    setLoading(false);
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      {loading ? (
        <ActivityIndicator size="large" color="#0000ff" />
      ) : token ? (
        <Text>Access Token: {token}</Text>
      ) : (
        <Button title="Login" onPress={handleLogin} />
      )}
    </View>
  );
}